function HearingTimeAllowedUnits() {}
HearingTimeAllowedUnits.dataBinding = "/ds/EnterVariableData/SmallTrack/hearingTimeAllowedUnits";
HearingTimeAllowedUnits.tabIndex = __tabIdx++;
HearingTimeAllowedUnits.helpText = "Select unit time";	
HearingTimeAllowedUnits.mandatoryOn = [HearingTimeAllowed.dataBinding];
HearingTimeAllowedUnits.isMandatory = function() { return HearingTimeAllowed.isMandatory(); }
HearingTimeAllowedUnits.enableOn = [HearingTimeAllowed.dataBinding];
HearingTimeAllowedUnits.isEnabled = function() { return HearingTimeAllowed.isEnabled(); }		
HearingTimeAllowedUnits.logicOn = [HearingTimeAllowed.dataBinding];
HearingTimeAllowedUnits.logic = function() {
	if(!HearingTimeAllowed.isEnabled())	Services.setValue(HearingTimeAllowedUnits.dataBinding,""); }
